    const presence = this.room.getSelf()?.presence;
    if (state === null) {
      if (presence === undefined) {
        // if presence is already undefined, we don't need to change anything here
        return;
      }
      this.room.updatePresence({ ...presence, [Y_PRESENCE_KEY]: null });
