      updateDoc(update, isRoot ? undefined : this.doc.guid);
    };
    this.fetchRoomDoc = (vector: string) => {
      fetchDoc(vector, isRoot ? undefined : this.doc.guid);
    };

    this.syncDoc();
  }

  public handleServerUpdate = ({
    update,
    stateVector,
    readOnly,
    v2,
