      editor._tiptapEditor.state.tr.insert(posInfo.posBeforeNode, nodesToInsert)
    );
  }

  if (placement === "after") {
    editor.dispatch(
      editor._tiptapEditor.state.tr.insert(
        posInfo.posBeforeNode + posInfo.node.nodeSize,
        nodesToInsert
      )
    );
