          destroy: () => {
            if (editor.prosemirrorView?.root instanceof ShadowRoot) {
              editor.prosemirrorView.root.removeChild(styleEl);
            } else {
              editor.prosemirrorView?.root.head.removeChild(styleEl);
            }
