  const ret: TableContent<I, S> = {
    type: "tableContent",
    columnWidths: [],
    rows: [],
  };

  contentNode.content.forEach((rowNode, _offset, index) => {
    const row: TableContent<I, S>["rows"][0] = {
      cells: [],
