","import { BlockNoteSchema } from "../editor/BlockNoteSchema.js";
import {
  BlockFromConfigNoChildren,
  BlockSchema,
  InlineContentFromConfig,
  InlineContentSchema,
  StyleSchema,
  Styles,
} from "../schema/index.js";
import type { Exporter } from "./Exporter.js";

/**
 * Defines a mapping from all block types with a schema to a result type `R`.
 */
export type BlockMapping<
  B extends BlockSchema,
  I extends InlineContentSchema,
  S extends StyleSchema,
  RB,
  RI
> = {
  [K in keyof B]: (
    block: BlockFromConfigNoChildren<B[K], I, S>,
    // we don't know the exact types that are supported by the exporter at this point,
    // because the mapping only knows about converting certain types (which might be a subset of the supported types)
    // this is why there are many `any` types here (same for types below)
    exporter: Exporter<any, any, any, RB, RI, any, any>,
    nestingLevel: number,
    numberedListIndex?: number
  ) => RB | Promise<RB>;
};

/**
 * Defines a mapping from all inline content types with a schema to a result type R.
 */
export type InlineContentMapping<
  I extends InlineContentSchema,
  S extends StyleSchema,
  RI,
  TS
> = {
  [K in keyof I]: (
    inlineContent: InlineContentFromConfig<I[K], S>,
    exporter: Exporter<any, I, S, any, RI, any, TS>
  ) => RI;
};

/**
 * Defines a mapping from all style types with a schema to a result type R.
 */
export type StyleMapping<S extends StyleSchema, RS> = {
  [K in keyof S]: (
    style: Styles<S>[K],
    exporter: Exporter<any, any, any, any, any, RS, any>
  ) => RS;
};

/**
 * The mapping factory is a utility function to easily create mappings for
 * a BlockNoteSchema. Using the factory makes it easier to get typescript code completion etc.
 */
export function mappingFactory<
  B extends BlockSchema,
  I extends InlineContentSchema,
  S extends StyleSchema
>(_schema: BlockNoteSchema<B, I, S>) {
  return {
    createBlockMapping: <R, RI>(mapping: BlockMapping<B, I, S, R, RI>) =>
      mapping,
    createInlineContentMapping: <R, RS>(
      mapping: InlineContentMapping<I, S, R, RS>
    ) => mapping,
    createStyleMapping: <R>(mapping: StyleMapping<S, R>) => mapping,
  };
}
","import type { Emoji, EmojiMartData } from "@emoji-mart/data";

import { checkDefaultInlineContentTypeInSchema } from "../../blocks/defaultBlockTypeGuards.js";
import { BlockNoteEditor } from "../../editor/BlockNoteEditor.js";
import {
  BlockSchema,
  InlineContentSchema,
  StyleSchema,
} from "../../schema/index.js";
import { DefaultGridSuggestionItem } from "./DefaultGridSuggestionItem.js";

let data:
  | Promise<{
      default: EmojiMartData;
    }>
  | undefined;

let emojiMart: typeof import("emoji-mart") | undefined;

export async function getDefaultEmojiPickerItems<
  BSchema extends BlockSchema,
  I extends InlineContentSchema,
  S extends StyleSchema
>(
  editor: BlockNoteEditor<BSchema, I, S>,
  query: string
): Promise<DefaultGridSuggestionItem[]> {
  if (!checkDefaultInlineContentTypeInSchema("text", editor)) {
    return [];
  }

  if (!data) {
    // use a dynamic import to encourage bundle-splitting
    // and a smaller initial client bundle size

    data = import("@emoji-mart/data") as any;

    // load dynamically because emoji-mart doesn't specify type: module and breaks in nodejs
    emojiMart = await import("emoji-mart");
    const emojiMartData = (await data)!.default;
    await emojiMart.init({ data: emojiMartData });
  }

  const emojiMartData = (await data)!.default;

  const emojisToShow =
    query.trim() === ""
      ? Object.values(emojiMartData.emojis)
      : ((await emojiMart!.SearchIndex.search(query)) as Emoji[]);

  return emojisToShow.map((emoji) => ({
    id: emoji.skins[0].native,
    onItemClick: () => editor.insertInlineContent(emoji.skins[0].native + " "),
  }));
}
","/**
 * Combines items by group. This can be used to combine multiple slash menu item arrays,
 * while making sure that items from the same group are adjacent to each other.
 */
export function combineByGroup<T extends { group?: string }>(
  items: T[],
  ...additionalItemsArray: {
    group?: string;
  }[][]
) {
  const combinedItems = [...items];
  for (const additionalItems of additionalItemsArray) {
    for (const additionalItem of additionalItems) {
      const lastItemWithSameGroup = combinedItems.findLastIndex(
        (item) => item.group === additionalItem.group
      );
      if (lastItemWithSameGroup === -1) {
        combinedItems.push(additionalItem as T);
      } else {
        combinedItems.splice(lastItemWithSameGroup + 1, 0, additionalItem as T);
      }
    }
  }
  return combinedItems;
}
","import { Block, PartialBlock } from "../../blocks/defaultBlocks.js";
import { BlockNoteSchema } from "../../editor/BlockNoteSchema.js";
import UniqueID from "../../extensions/UniqueID/UniqueID.js";
import { BlockSchema, TableContent } from "../../schema/blocks/types.js";
import {
  InlineContent,
  InlineContentSchema,
  PartialInlineContent,
  StyledText,
  isPartialLinkInlineContent,
  isStyledTextInlineContent,
} from "../../schema/inlineContent/types.js";
import { StyleSchema } from "../../schema/styles/types.js";

function textShorthandToStyledText(
  content: string | StyledText<any>[] = ""
): StyledText<any>[] {
  if (typeof content === "string") {
    return [
      {
        type: "text",
        text: content,
        styles: {},
      },
    ];
  }
  return content;
}

function partialContentToInlineContent(
  content: PartialInlineContent<any, any> | TableContent<any> | undefined
): InlineContent<any, any>[] | TableContent<any> | undefined {
  if (typeof content === "string") {
    return textShorthandToStyledText(content);
  }

  if (Array.isArray(content)) {
    return content.flatMap((partialContent) => {
      if (typeof partialContent === "string") {
        return textShorthandToStyledText(partialContent);
      } else if (isPartialLinkInlineContent(partialContent)) {
        return {
          ...partialContent,
          content: textShorthandToStyledText(partialContent.content),
        };
      } else if (isStyledTextInlineContent(partialContent)) {
        return partialContent;
      } else {
        // custom inline content

        return {
          props: {},
          ...partialContent,
          content: partialContentToInlineContent(partialContent.content),
        } as any;
      }
    });
  } else if (content?.type === "tableContent") {
    return {
      type: "tableContent",
      columnWidths: content.columnWidths,
      rows: content.rows.map((row) => ({
        ...row,
        cells: row.cells.map(
          (cell) => partialContentToInlineContent(cell) as any
        ),
      })),
    };
  }

  return content;
}

export function partialBlocksToBlocksForTesting<
  BSchema extends BlockSchema,
  I extends InlineContentSchema,
  S extends StyleSchema
>(
  schema: BlockNoteSchema<BSchema, I, S>,
  partialBlocks: Array<PartialBlock<NoInfer<BSchema>, NoInfer<I>, NoInfer<S>>>
): Array<Block<BSchema, I, S>> {
  return partialBlocks.map((partialBlock) =>
    partialBlockToBlockForTesting(schema.blockSchema, partialBlock)
  );
}

export function partialBlockToBlockForTesting<
  BSchema extends BlockSchema,
  I extends InlineContentSchema,
  S extends StyleSchema
>(
  schema: BSchema,
  partialBlock: PartialBlock<BSchema, I, S>
): Block<BSchema, I, S> {
  const contentType: "inline" | "table" | "none" =
    schema[partialBlock.type!].content;

  const withDefaults: Block<BSchema, I, S> = {
    id: "",
    type: partialBlock.type!,
    props: {} as any,
    content:
      contentType === "inline"
        ? []
        : contentType === "table"
        ? { type: "tableContent", columnWidths: [], rows: [] }
        : (undefined as any),
    children: [] as any,
    ...partialBlock,
  };

  Object.entries(schema[partialBlock.type!].propSchema).forEach(
    ([propKey, propValue]) => {
      if (
        withDefaults.props[propKey] === undefined &&
        propValue.default !== undefined
      ) {
        (withDefaults.props as any)[propKey] = propValue.default;
      }
    }
  );

  if (contentType === "inline") {
    const content = withDefaults.content as InlineContent<I, S>[] | undefined;
    withDefaults.content = partialContentToInlineContent(content) as any;
  } else if (contentType === "table") {
    const content = withDefaults.content as TableContent<I, S> | undefined;
    withDefaults.content = {
      type: "tableContent",
      columnWidths:
        content?.columnWidths ||
        content?.rows[0]?.cells.map(() => undefined) ||
        [],
      rows:
        content?.rows.map((row) => ({
          cells: row.cells.map((cell) => partialContentToInlineContent(cell)),
        })) || [],
    } as any;
  }

  return {
    ...withDefaults,
    content: partialContentToInlineContent(withDefaults.content),
    children: withDefaults.children.map((c) => {
      return partialBlockToBlockForTesting(schema, c);
    }),
  } as any;
}

export function addIdsToBlock(block: PartialBlock<any, any, any>) {
  if (!block.id) {
    block.id = UniqueID.options.generateID();
  }
  if (block.children) {
    addIdsToBlocks(block.children);
  }
}

export function addIdsToBlocks(blocks: PartialBlock<any, any, any>[]) {
  for (const block of blocks) {
    addIdsToBlock(block);
  }
}
